   116→template <class S, class F, class RQ, class RS>
   117→Config::GrpcMuxWatchPtr GrpcMuxImpl<S, F, RQ, RS>::addWatch(
   118→    const std::string& type_url, const absl::flat_hash_set<std::string>& resources,
   119→    SubscriptionCallbacks& callbacks, OpaqueResourceDecoderSharedPtr resource_decoder,
   120→    const SubscriptionOptions& options) {
   121→  auto watch_map = watch_maps_.find(type_url);
   122→  if (watch_map == watch_maps_.end()) {
   123→    // Resource cache is only used for EDS resources.
   124→    EdsResourcesCacheOptRef resources_cache{absl::nullopt};
   125→    if (eds_resources_cache_ &&
   126→        (type_url == Config::getTypeUrl<envoy::config::endpoint::v3::ClusterLoadAssignment>())) {
   127→      resources_cache = makeOptRefFromPtr(eds_resources_cache_.get());
   128→    }
   129→
   130→    // We don't yet have a subscription for type_url! Make one!
   131→    watch_map = watch_maps_
   132→                    .emplace(type_url,
   133→                             std::make_unique<WatchMap>(options.use_namespace_matching_, type_url,
   134→                                                        *config_validators_.get(), resources_cache))
   135→                    .first;
   136→    subscriptions_.emplace(type_url, subscription_state_factory_->makeSubscriptionState(
   137→                                         type_url, *watch_maps_[type_url], resource_decoder,
   138→                                         xds_config_tracker_, xds_resources_delegate_,
   139→                                         target_xds_authority_));
   140→    subscription_ordering_.emplace_back(type_url);
   141→  }
   142→
   143→  Watch* watch = watch_map->second->addWatch(callbacks, *resource_decoder);
   144→  // updateWatch() queues a discovery request if any of 'resources' are not yet subscribed.
   145→  updateWatch(type_url, watch, resources, options);
   146→  return std::make_unique<WatchImpl>(type_url, watch, *this, options);
   147→}
   148→
   149→// Updates the list of resource names watched by the given watch. If an added name is new across
   150→// the whole subscription, or if a removed name has no other watch interested in it, then the
   151→// subscription will enqueue and attempt to send an appropriate discovery request.
   152→template <class S, class F, class RQ, class RS>
   153→void GrpcMuxImpl<S, F, RQ, RS>::updateWatch(const std::string& type_url, Watch* watch,
   154→                                            const absl::flat_hash_set<std::string>& resources,
   155→                                            const SubscriptionOptions& options) {
   156→  ENVOY_LOG(debug, "GrpcMuxImpl::updateWatch for {}", type_url);
   157→  ASSERT(watch != nullptr);
   158→  auto& sub = subscriptionStateFor(type_url);
   159→  WatchMap& watch_map = watchMapFor(type_url);
   160→
   161→  // We need to prepare xdstp:// resources for the transport, by normalizing and adding any extra
   162→  // context parameters.
   163→  absl::flat_hash_set<std::string> effective_resources;
   164→  for (const auto& resource : resources) {
   165→    if (XdsResourceIdentifier::hasXdsTpScheme(resource)) {
   166→      auto xdstp_resource_or_error = XdsResourceIdentifier::decodeUrn(resource);
   167→      THROW_IF_STATUS_NOT_OK(xdstp_resource_or_error, throw);
   168→      auto xdstp_resource = xdstp_resource_or_error.value();
   169→      if (options.add_xdstp_node_context_params_) {
   170→        const auto context = XdsContextParams::encodeResource(
   171→            local_info_.contextProvider().nodeContext(), xdstp_resource.context(), {}, {});
   172→        xdstp_resource.mutable_context()->CopyFrom(context);
   173→      }
   174→      XdsResourceIdentifier::EncodeOptions encode_options;
   175→      encode_options.sort_context_params_ = true;
   176→      effective_resources.insert(XdsResourceIdentifier::encodeUrn(xdstp_resource, encode_options));
   177→    } else {
   178→      effective_resources.insert(resource);
   179→    }
   180→  }
   181→
   182→  auto added_removed = watch_map.updateWatchInterest(watch, effective_resources);
   183→  if (options.use_namespace_matching_) {
   184→    // This is to prevent sending out of requests that contain prefixes instead of resource names
   185→    sub.updateSubscriptionInterest({}, {});
   186→  } else {
   187→    sub.updateSubscriptionInterest(added_removed.added_, added_removed.removed_);
   188→  }
   189→
   190→  // Tell the server about our change in interest, if any.
   191→  if (sub.subscriptionUpdatePending()) {
   192→    trySendDiscoveryRequests();
   193→  }
   194→}
